"use client";

import { FileText } from "lucide-react";

export interface BoletimData {
  id: string;
  nome: string;
  partes: string;
}

interface Props {
  data: BoletimData;
  onChange: (data: BoletimData) => void;
}

function Field({
  label,
  value,
  onChange,
  placeholder,
  className = "",
}: {
  label: string;
  value: string;
  onChange: (v: string) => void;
  placeholder?: string;
  className?: string;
}) {
  return (
    <div className={`flex flex-col gap-1 ${className}`}>
      <label className="text-[10px] font-semibold uppercase tracking-widest text-slate-500">
        {label}
      </label>
      <input
        type="text"
        value={value}
        onChange={(e) => onChange(e.target.value)}
        placeholder={placeholder}
        className="bg-slate-800/60 border border-slate-700 rounded-lg px-3 py-1.5 text-sm text-slate-200 placeholder-slate-600 outline-none focus:border-teal-600/60 focus:ring-1 focus:ring-teal-600/20 transition-all"
      />
    </div>
  );
}

export default function BoletimForm({ data, onChange }: Props) {
  const set = (key: keyof BoletimData) => (val: string) =>
    onChange({ ...data, [key]: val });

  return (
    <div className="bg-slate-900 ring-1 ring-slate-700 rounded-xl px-4 py-3">
      <div className="flex items-center gap-2 mb-3">
        <FileText size={13} className="text-slate-500" />
        <span className="text-[10px] font-semibold uppercase tracking-widest text-slate-500">
          Dados do Boletim
        </span>
      </div>

      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
        <Field
          label="ID"
          value={data.id}
          onChange={set("id")}
          placeholder="ex: 1234"
        />
        <Field
          label="Nome"
          value={data.nome}
          onChange={set("nome")}
          placeholder="Nome completo"
          className="sm:col-span-3"
        />
        <Field
          label="Partes da Ocorrência"
          value={data.partes}
          onChange={set("partes")}
          placeholder="Envolvidos, vítimas..."
          className="col-span-2 sm:col-span-4"
        />
      </div>
    </div>
  );
}
